    scriptLayout: '',
    isGeneratingScript: false,
    script: null,
    images: {},
    videoPrompts: {}
  });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const faceInputRef = useRef<HTMLInputElement>(null);
  const outfitInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed && typeof parsed === 'object') {
          setState((prev: any) => ({
            ...prev,
            ...parsed,
            selectedFiles: [],
            previewUrls: [],
            faceFile: null,
            facePreviewUrl: null,
            outfitFile: null,
            outfitPreviewUrl: null,
            isGeneratingScript: false,
            isExtractingOutfit: false
          }));
        }
      }
    } catch (e) {
      console.error("Failed to restore KOC state", e);
    }
  }, []);

  useEffect(() => {
    try {
      const { isGeneratingScript, isExtractingOutfit, selectedFiles, previewUrls, faceFile, facePreviewUrl, outfitFile, outfitPreviewUrl, images, ...persistentData } = state;
      const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
        acc[key] = { ...images[key], url: '' };
        return acc;
      }, {});
      localStorage.setItem(storageKey, JSON.stringify({ ...persistentData, images: safeImages }));
    } catch (e) {
      console.error("Failed to save KOC state due to quota", e);
    }
  }, [state]);

  // Merge: Add Import/Export logic back in
  useEffect(() => {
    const handleExport = () => {
      const exportData = getActiveKeys(state.sceneCount).map((key, index) => ({
        stt: index + 1,
        inputs: {
          productName: state.productName,
          keyword: state.keyword,
          characterDescription: state.characterDescription,
          outfitDescription: state.outfitDescription,
          visualNote: state.visualNote,
          settings: {
            gender: state.gender,
            voice: state.voice,
            tone: state.scriptTone,
            layout: state.scriptLayout,
            imageStyle: state.imageStyle
          }
        },
        script: state.script ? state.script[key] : '',
        outputImage: state.images[key]?.url || '',
        videoPrompt: state.videoPrompts[key]?.text || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', {
        detail: { data: exportData, moduleName: 'KOC_Review_Visual' }
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData)) return;

      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};
      const settings = smartFind(inputs, ['settings', 'config']) || {};

      const newState = {
        ...state,
        productName: smartFind(inputs, ['productName', 'name', 'sản phẩm']) || state.productName,
        keyword: smartFind(inputs, ['keyword', 'usp', 'từ khóa']) || state.keyword,
        characterDescription: smartFind(inputs, ['characterDescription', 'character', 'nhân vật']) || state.characterDescription,
        outfitDescription: smartFind(inputs, ['outfitDescription', 'outfit', 'trang phục']) || state.outfitDescription,
        visualNote: smartFind(inputs, ['visualNote', 'hiển thị']) || state.visualNote,
        gender: smartFind(settings, ['gender', 'giới tính']) || state.gender,
        voice: smartFind(settings, ['voice', 'giọng']) || state.voice,
        imageStyle: smartFind(settings, ['imageStyle', 'style', 'phong cách']) || state.imageStyle,
        sceneCount: importedData.length,
        script: {},
        images: {},
        videoPrompts: {}
      };

      const total = importedData.length;
      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const key = `v${i + 1}`;

        const scriptVal = smartFind(item, ['script', 'content', 'kịch bản', 'text']) || '';
        const imgVal = smartFind(item, ['outputImage', 'image', 'base64']) || '';
        const promptVal = smartFind(item, ['videoPrompt', 'prompt', 'video']) || '';

        newState.script[key] = scriptVal;
        newState.images[key] = { url: imgVal, loading: false, customPrompt: '' };
        newState.videoPrompts[key] = { text: promptVal, loading: false, visible: !!promptVal };

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', {
          detail: { percent, complete: i === total - 1 }
        }));

        await new Promise(r => setTimeout(r, 100));
      }

      setState(newState);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [state]);

  const getActiveKeys = (count: number): ScriptPartKey[] => {
    const keys: string[] = [];
    for (let i = 1; i <= count; i++) {
      keys.push(`v${i}`);
    }
    return keys;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = [e.target.files[0]];
      setState((prev: any) => ({
        ...prev,
        selectedFiles: files,
        previewUrls: [URL.createObjectURL(files[0])]
      }));
    }
  };

  const handleFaceFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({
        ...prev,
        faceFile: file,
        facePreviewUrl: URL.createObjectURL(file)
      }));
    }
  };

  const handleOutfitFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({
        ...prev,
        outfitFile: file,
        outfitPreviewUrl: URL.createObjectURL(file),
        outfitDescription: ''
      }));
    }
  };

  const handleExtractOutfit = async () => {
    if (!state.outfitFile) return;
    setState(p => ({ ...p, isExtractingOutfit: true }));
    try {
      const part = await service.fileToGenerativePart(state.outfitFile);
      const desc = await service.describeKocOutfit(part);
      setState(p => ({ ...p, outfitDescription: desc, isExtractingOutfit: false }));
    } catch (e) {
      console.error(e);
      setState(p => ({ ...p, isExtractingOutfit: false }));
    }
  };

  const handleGenerate = async () => {
    if (state.selectedFiles.length === 0 || !state.productName) return;

    const activeKeys = getActiveKeys(state.sceneCount);
    const initialImages: any = {};
    const initialPrompts: any = {};
    activeKeys.forEach(k => {
      initialImages[k] = { url: '', loading: false, customPrompt: '' };
      initialPrompts[k] = { text: '', loading: false, visible: false };
    });

    setState((prev: any) => ({
      ...prev,
      isGeneratingScript: true,
      script: null,
      images: initialImages,
      videoPrompts: initialPrompts
    }));

    try {
      const imageParts = await Promise.all(state.selectedFiles.map(file => service.fileToGenerativePart(file)));

      let layoutToUse = state.scriptLayout;
      if (!layoutToUse) layoutToUse = LAYOUT_OPTIONS[Math.floor(Math.random() * LAYOUT_OPTIONS.length)];

      const script = await service.generateKocScript(
        imageParts,
        state.productName,
        state.keyword,
        state.scriptTone,
        state.productSize,
        state.scriptNote,
        layoutToUse,
        state.gender,
        state.voice,
        state.sceneCount
      );
      setState((prev: any) => ({ ...prev, script, scriptLayout: layoutToUse }));
    } catch (e) {
      console.error(e);
    } finally {
      setState((prev: any) => ({ ...prev, isGeneratingScript: false }));
    }
  };

  const handleGenImageForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: true } } }));
    try {
      const imageParts = await Promise.all(state.selectedFiles.map(file => service.fileToGenerativePart(file)));
      const facePart = state.faceFile ? await service.fileToGenerativePart(state.faceFile) : null;
      const outfitPart = state.outfitFile ? await service.fileToGenerativePart(state.outfitFile) : null;

      const url = await service.generateKocImage(
        imageParts,
        facePart,
        outfitPart,
        state.outfitDescription,
        state.productName,
        state.script[key],
        state.characterDescription,
        state.images[key]?.customPrompt,
        state.gender,
        state.imageStyle,
        state.scriptNote,
        state.visualNote
      );
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], url, loading: false } } }));
    } catch (e) {
      console.error(e);
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: false, error: 'Failed' } } }));
    }
  };

  const handleGeneratePromptForKey = async (key: string) => {
    setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: true, visible: true } } }));
    try {
      const productImagePart = state.selectedFiles[0] ? await service.fileToGenerativePart(state.selectedFiles[0]) : null;

      const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
      const customPrompt = state.images[key]?.customPrompt || "";
      const isNoProduct = noProductKeywords.some(kw => customPrompt.toLowerCase().includes(kw));

      const prompt = await service.generateKocVeoPrompt(
        state.productName,
        state.script[key],
        state.gender,
        state.voice,
        productImagePart?.data,
        state.images[key].url,
        isNoProduct,
        state.imageStyle
      );
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (e) {
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } }));
    }
  };

  const handleBulkPrompt = async () => {
    const keys = getActiveKeys(state.sceneCount);
    for (const key of keys) {
      await handleGeneratePromptForKey(key);
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') {
      alert("Đang tải thư viện nén, vui lòng thử lại sau giây lát.");
      return;
    }

    const zip = new JSZip();
    const activeKeys = getActiveKeys(state.sceneCount);
    let count = 0;

    for (let i = 0; i < activeKeys.length; i++) {
      const key = activeKeys[i];
      const imageData = state.images[key];
      if (imageData?.url) {
        const base64Data = imageData.url.split(',')[1];
        if (base64Data) {
          const fileName = `${String(i + 1).padStart(2, '0')}.png`;
          zip.file(fileName, base64Data, { base64: true });
          count++;
        }
      }
    }

    if (count === 0) {
      alert("Không có ảnh nào để tải xuống.");
      return;
    }

    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `koc_images_${state.productName || 'project'}.zip`;
    link.click();
  };

  const downloadAllPrompts = () => {
    const activeKeys = getActiveKeys(state.sceneCount);
    const text = activeKeys
      .map(key => state.videoPrompts[key]?.text || "")
      .filter(t => t.trim().length > 0)
      .map(t => t.replace(/\n/g, ' '))
      .join('\n');

    if (!text) {
      alert("Vui lòng tạo Video Prompt trước khi tải xuống.");
      return;
    }

    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `prompts_${state.productName || 'koc'}.txt`;
    link.click();
  };

  const activeKeys = getActiveKeys(state.sceneCount);
  const hasGeneratedItems = state.script && Object.values(state.images).some((img: any) => img.url);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 mb-8">
        <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
          <div className="md:col-span-5 flex flex-col gap-4">
            <label className="block text-sm font-bold text-slate-700">1. Hình ảnh sản phẩm (1 ảnh duy nhất)</label>
            <div onClick={() => fileInputRef.current?.click()} className="relative w-full aspect-video rounded-xl border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors overflow-hidden border-[#ff5722]/20">
              {state.previewUrls[0] ? <img src={state.previewUrls[0]} className="h-full object-contain" /> : <span className="text-slate-400 text-sm">Tải ảnh sản phẩm</span>}
              <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" />
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Ghi chú nhân vật</label>
              <textarea
                value={state.characterDescription}
                onChange={e => setState(p => ({ ...p, characterDescription: e.target.value }))}
                placeholder="Mô tả phong cách, diện mạo nhân vật..."
                className="w-full p-3 border rounded-xl h-24 text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-sm font-bold text-slate-700">0. Ảnh mặt mẫu</label>
                <div onClick={() => faceInputRef.current?.click()} className="relative w-full aspect-square rounded-xl border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors overflow-hidden">
                  {state.facePreviewUrl ? <img src={state.facePreviewUrl} className="h-full object-cover" /> : <span className="text-slate-400 text-[10px] uppercase font-bold text-center p-2">Mặt mẫu</span>}
                  <input type="file" ref={faceInputRef} onChange={handleFaceFileChange} className="hidden" accept="image/*" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="block text-sm font-bold text-slate-700">2. Ảnh trang phục</label>
                <div onClick={() => outfitInputRef.current?.click()} className="relative w-full aspect-square rounded-xl border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors overflow-hidden">
                  {state.outfitPreviewUrl ? <img src={state.outfitPreviewUrl} className="h-full object-cover" /> : <span className="text-slate-400 text-[10px] uppercase font-bold text-center p-2">Trang phục</span>}
                  <input type="file" ref={outfitInputRef} onChange={handleOutfitFileChange} className="hidden" accept="image/*" />
                </div>
                {state.outfitFile && (
                  <button
                    onClick={handleExtractOutfit}
                    disabled={state.isExtractingOutfit}
                    className={`w-full py-2 rounded-lg text-[10px] font-black uppercase transition-all shadow-sm ${state.outfitDescription ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-blue-600 text-white hover:bg-blue-700'}`}
                  >
                    {state.isExtractingOutfit ? "Đang tách..." : state.outfitDescription ? "Đã tách xong ✓" : "Tách trang phục"}
                  </button>
                )}
              </div>
            </div>

            {state.outfitDescription && (
              <div className="p-3 bg-slate-50 border rounded-xl animate-fadeIn">
                <label className="block text-[8px] font-black text-slate-400 uppercase mb-1">Kết quả tách trang phục (AI focus):</label>
                <p className="text-[10px] text-slate-600 italic leading-relaxed line-clamp-3">"{state.outfitDescription}"</p>
              </div>
            )}
          </div>
          <div className="md:col-span-7 space-y-4">
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Tên sản phẩm</label>
                <input type="text" value={state.productName} onChange={e => setState(p => ({ ...p, productName: e.target.value }))} placeholder="Nhập tên sản phẩm..." className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all" />
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">USP sản phẩm (Đặc điểm nổi bật, công dụng, giá trị...)</label>
                <textarea
                  value={state.keyword}
                  onChange={e => setState(p => ({ ...p, keyword: e.target.value }))}
                  placeholder="Điền các điểm USP nổi bật của sản phẩm..."
                  className="w-full p-3 border rounded-xl h-24 text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Ghi chú hiển thị (Visual Appearance)</label>
                <textarea
                  value={state.visualNote}
                  onChange={e => setState(p => ({ ...p, visualNote: e.target.value }))}
                  placeholder="Mô tả cách sản phẩm và nhân vật xuất hiện (VD: nhân vật đứng cạnh sản phẩm, sản phẩm chiếm 60% khung hình...)"
                  className="w-full p-3 border rounded-xl h-20 text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Giới tính nhân vật</label>
                <select value={state.gender} onChange={e => setState(p => ({ ...p, gender: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none">
                  <option value="Nữ">Nữ</option>
                  <option value="Nam">Nam</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Giọng điệu</label>
                <select value={state.voice} onChange={e => setState(p => ({ ...p, voice: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none">
                  <option value="Miền Bắc">Miền Bắc</option>
                  <option value="Miền Nam">Miền Nam</option>
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Thời lượng (Scenes)</label>
                <select value={state.sceneCount} onChange={e => setState(p => ({ ...p, sceneCount: parseInt(e.target.value) }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none font-bold text-orange-600">
                  {SCENE_COUNT_OPTIONS.map(opt => (
                    <option key={opt.count} value={opt.count}>{opt.label}</option>
                  ))}
                </select>
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Phong cách ảnh</label>
                <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-200">
                  <button
                    onClick={() => setState(p => ({ ...p, imageStyle: 'Realistic' }))}
                    className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${state.imageStyle === 'Realistic' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    Chân thực
                  </button>
                  <button
                    onClick={() => setState(p => ({ ...p, imageStyle: '3D' }))}
                    className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${state.imageStyle === '3D' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    3D Animation
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Bố cục kịch bản (Layout)</label>
              <select value={state.scriptLayout} onChange={e => setState(p => ({ ...p, scriptLayout: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none">
                <option value="">-- Random Layout --</option>
                {LAYOUT_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}
              </select>
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Background bối cảnh (Chỉ dùng cho ảnh)</label>
              <textarea
                value={state.scriptNote}
                onChange={e => setState(p => ({ ...p, scriptNote: e.target.value }))}
                placeholder="Mô tả bối cảnh chi tiết (phòng khách, quán cafe...) - Sẽ KHÔNG được nhắc đến trong kịch bản chữ."
                className="w-full p-3 border rounded-xl h-28 text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all"
              />
            </div>

            <button onClick={handleGenerate} disabled={state.isGeneratingScript} className="w-full py-4 bg-orange-600 text-white font-black rounded-xl shadow-lg disabled:opacity-50 hover:bg-orange-700 transition-all active:scale-[0.98] uppercase tracking-widest">
              {state.isGeneratingScript ? "Đang xử lý kịch bản..." : "Bắt đầu tạo kịch bản"}
            </button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-8 pb-32">
          <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-sm">
            <h3 className="text-sm font-black text-white uppercase tracking-tight">KẾT QUẢ CHIẾN DỊCH</h3>
            <p className="text-[10px] font-bold text-orange-500 uppercase tracking-widest">
              Đã tạo xong {activeKeys.length} cảnh ({activeKeys.length * 8}s) • Style: {state.imageStyle === 'Realistic' ? 'Chân thực' : '3D Animation'}
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
            {activeKeys.map((key, idx) => (
              <div key={key} className="space-y-4">
                <ScriptSection
                  title={`Phần ${idx + 1}`}
                  content={state.script[key]}
                  color="border-orange-500"
                  onChange={(val) => setState(p => ({ ...p, script: { ...p.script, [key]: val } }))}
                />
                <ImageCard
                  label={`Cảnh ${idx + 1}`}
                  imageData={state.images[key]}
                  videoPrompt={state.videoPrompts[key]}
                  onGeneratePrompt={() => handleGeneratePromptForKey(key)}
                  onRegenerate={() => handleGenImageForKey(key)}
                  onTranslate={() => { }}
                  customPrompt={state.images[key]?.customPrompt || ''}
