                }`}>
                  {activeProductId === p.id && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
                </div>
                <span className={`text-[11px] font-bold ${activeProductId === p.id ? 'text-[#ff5722]' : 'text-slate-500'}`}>
                  Sản phẩm {p.id}
                </span>
              </div>

              <div 
