                </div>
              </div>

              {/* Bulk Actions for Product */}
              <div className="flex justify-center mt-10 gap-4">
                <button 
                    onClick={() => handleBulkImageForProduct(product.id)} 
                    className="px-10 py-4 bg-orange-600 text-white font-black rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all text-sm flex items-center gap-4 uppercase tracking-widest"
                >
