      for (const key of keys) {
        const prompt = product.videoPrompts[key];
        if (prompt && prompt.text) {
          const cleanPrompt = prompt.text.replace(/\r?\n/g, ' ').trim();
          allPromptsContent += cleanPrompt + "\n";
          promptCount++;
        }
      }
    }

    if (promptCount === 0) {
      alert("Chưa có video prompt nào được tạo để tải xuống.");
      return;
    }

    const blob = new Blob([allPromptsContent], { type: 'text/plain;charset=utf-8' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "shopee8s_prompts.txt";
    link.click();
  };

  const productsWithResults = products.filter(p => p.script);
  const hasResults = productsWithResults.length > 0;
  const hasAnyMedia = products.some(p => 
