                        className={`flex-1 text-[10px] font-black uppercase rounded-lg transition-all ${imageStyle === 'Realistic' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                      >
                        Chân thực
                      </button>
                      <button 
