              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-[11px] font-bold text-slate-500 uppercase tracking-widest px-1">3. Ý tưởng câu chuyện / Chủ đề:</label>
              <textarea 
                value={state.storyIdea} 
