áp dụng các phần còn thiếu trong đoạn code dưới đây vào file fashion16smodule:


import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/fashion16sService';
import { FashionImageItem, FashionScenarioPart } from '../types';

declare var JSZip: any;

const BODY_TYPES = [
  { label: 'Cân đối', prompt: 'well-proportioned body, average height, balanced shoulders and hips, healthy physique' },
  { label: 'Cao gầy', prompt: 'tall and slender body, long limbs, narrow shoulders, low body fat' },
  { label: 'Chubby (mập vừa, dễ thương)', prompt: 'slightly overweight body, soft curves, round face, visible belly, cute appearance' },
  { label: 'Béo lùn', prompt: 'short height, stocky body, round torso, short limbs, high body fat' },
  { label: 'Gầy nhỏ người', prompt: 'short and slim body, small frame, low body fat' },
  { label: 'Đầy đặn, phúc hậu', prompt: 'full-bodied, proportionate, soft and rounded silhouette' },
  { label: 'Cơ bắp / săn chắc', prompt: 'athletic body, muscular definition, low body fat' }
];

const FASHION_ACTIONS = [
  "Người mẫu đi thẳng về phía trước", "Xoay người nhẹ 180° hoặc 360°", "Đứng tạo dáng, dồn trọng tâm sang một bên",
  "Chỉnh áo, kéo khóa, cài cúc", "Vuốt cổ áo, xắn tay áo", "Vén tóc sau tai", "Đi bộ nhẹ lên phía trước",
  "Tạo dáng dứt khoát", "Dáng đứng nhấn vai, hông", "Ánh mắt mạnh, nghiêng đầu", "Tay chống hông",
  "Vải bay nhẹ theo gió", "Quay đầu chậm", "Nghiêng người về camera", "Mỉm cười nhẹ", "Tay cầm túi xách",
  "Vuốt nhẹ thân áo", "Kéo nhẹ gấu váy", "Dừng lại, xoay đầu chậm", "Đứng nghiêng người 45 độ",
  "Khoanh tay trước ngực", "Một tay đút túi quần", "Tay chạm nhẹ vào cổ", "Cúi đầu nhẹ nhìn xuống",
  "Bước đi chậm rãi phong thái catwalk", "Xoay vai nhìn lại phía sau", "Tay chỉnh kính râm (nếu có)",
  "Tay vuốt tóc nhẹ nhàng", "Dáng đứng tự tin, mắt nhìn thẳng", "Nở nụ cười rạng rỡ với camera"
];

const Fashion16sModule: React.FC = () => {
  const storageKey = "fashion16s_state_v17_scenario_4outfits";
  const [state, setState] = useState({
    faceFile: null as File | null,
    facePreview: null as string | null,
    backgroundFile: null as File | null,
    backgroundPreview: null as string | null,
    outfitFiles: [null, null, null, null] as (File | null)[],
    outfitPreviews: [null, null, null, null] as (string | null)[],
    backgroundNotes: '',
    characterDescription: '',
    gender: 'Nữ',
    bodyType: BODY_TYPES[0].label,
    selectedActions: [] as string[],
    imageStyle: 'Realistic' as 'Realistic' | '3D',
    isGenerating: false,
    isScenarioLoading: false,
    scenario: [] as FashionScenarioPart[],
    images: [] as FashionImageItem[]
  });

  const faceInputRef = useRef<HTMLInputElement>(null);
  const backgroundInputRef = useRef<HTMLInputElement>(null);
  const outfitRefs = [
    useRef<HTMLInputElement>(null), 
    useRef<HTMLInputElement>(null), 
    useRef<HTMLInputElement>(null),
    useRef<HTMLInputElement>(null)
  ];

  useEffect(() => {
    const saved = localStorage.getItem(storageKey);
    if (saved) {
      const parsed = JSON.parse(saved);
      setState(p => ({
        ...p,
        backgroundNotes: parsed.backgroundNotes || '',
        characterDescription: parsed.characterDescription || '',
        gender: parsed.gender || 'Nữ',
        bodyType: parsed.bodyType || BODY_TYPES[0].label,
        selectedActions: parsed.selectedActions || [],
        imageStyle: parsed.imageStyle || 'Realistic',
        scenario: parsed.scenario || [],
        images: (parsed.images || []).map((img: any) => ({ ...img, url: '', loading: false }))
      }));
    }
  }, []);

  useEffect(() => {
    const toSave = {
      backgroundNotes: state.backgroundNotes,
      characterDescription: state.characterDescription,
      gender: state.gender,
      bodyType: state.bodyType,
      selectedActions: state.selectedActions,
      imageStyle: state.imageStyle,
      scenario: state.scenario,
      images: state.images.map(img => ({ ...img, url: '' }))
    };
    localStorage.setItem(storageKey, JSON.stringify(toSave));
  }, [state.backgroundNotes, state.characterDescription, state.gender, state.bodyType, state.selectedActions, state.imageStyle, state.images, state.scenario]);

  useEffect(() => {
    const handleExport = () => {
      const exportData = state.images.map((img, index) => ({
        stt: index + 1,
        inputs: {
          characterDescription: state.characterDescription,
          backgroundNotes: state.backgroundNotes,
          scenarioPart: img.scenarioPart,
          settings: {
            gender: state.gender,
            bodyType: state.bodyType,
            imageStyle: state.imageStyle,
            outfitIndex: img.outfitIndex
          }
        },
        script: `Fashion Scene: ${img.scenarioPart || 'Pose'}`,
        outputImage: img.url || '',
        videoPrompt: img.videoPrompt || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Fashion_Collection' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj || {}).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData)) return;

      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};
      const settings = smartFind(inputs, ['settings', 'config']) || {};

      const newState = {
        ...state,
        characterDescription: smartFind(inputs, ['characterDescription', 'character']) || state.characterDescription,
        backgroundNotes: smartFind(inputs, ['backgroundNotes', 'background']) || state.backgroundNotes,
        gender: smartFind(settings, ['gender', 'giới tính']) || state.gender,
        bodyType: smartFind(settings, ['bodyType', 'dáng người']) || state.bodyType,
        imageStyle: smartFind(settings, ['imageStyle']) || state.imageStyle,
        images: [] as FashionImageItem[]
      };

      const total = importedData.length;
      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const itemSettings = smartFind(item, ['settings', 'config']) || {};

        newState.images.push({
          id: `imported-${i}-${Date.now()}`,
          outfitIndex: smartFind(itemSettings, ['outfitIndex']) || 0,
          url: smartFind(item, ['outputImage', 'image', 'base64']) || '',
          loading: false,
          regenNote: '',
          videoPrompt: smartFind(item, ['videoPrompt', 'prompt']) || '',
          isPromptLoading: false,
          isPromptVisible: true,
          scenarioPart: smartFind(item, ['script', 'content']) || ''
        });

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === total - 1 } }));
        await new Promise(r => setTimeout(r, 100));
      }

      setState(newState as any);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [state]);

  const handleFaceUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) setState(p => ({ ...p, faceFile: file, facePreview: URL.createObjectURL(file) }));
  };

  const handleBackgroundUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) setState(p => ({ ...p, backgroundFile: file, backgroundPreview: URL.createObjectURL(file) }));
  };

  const handleOutfitUpload = (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const newFiles = [...state.outfitFiles];
      const newPreviews = [...state.outfitPreviews];
      newFiles[index] = file;
      newPreviews[index] = URL.createObjectURL(file);
      setState(p => ({ ...p, outfitFiles: newFiles, outfitPreviews: newPreviews }));
    }
  };

  const toggleAction = (action: string) => {
    setState(p => {
      const exists = p.selectedActions.includes(action);
      return { ...p, selectedActions: exists ? p.selectedActions.filter(a => a !== action) : [...p.selectedActions, action] };
    });
  };

  const handleGenerateScenario = async () => {
    const validOutfits = state.outfitPreviews.filter(p => p !== null) as string[];
    if (validOutfits.length === 0) return alert("Vui lòng tải ít nhất 1 ảnh trang phục.");
    setState(p => ({ ...p, isScenarioLoading: true }));
    try {
      const scenario = await service.generateFashionScenario(validOutfits, state.gender);
      setState(p => ({ ...p, scenario, isScenarioLoading: false }));
    } catch (e) { setState(p => ({ ...p, isScenarioLoading: false })); }
  };

  const handleGenerateImages = async () => {
    const validOutfits = state.outfitFiles.filter(f => f !== null) as File[];
    if (!state.faceFile || validOutfits.length === 0) return alert("Cần ít nhất 1 ảnh mặt và 1 ảnh trang phục.");
    setState(p => ({ ...p, isGenerating: true }));
    try {
      const facePart = await service.fileToGenerativePart(state.faceFile);
      const bgPart = state.backgroundFile ? await service.fileToGenerativePart(state.backgroundFile) : null;
      const bodyTypePrompt = BODY_TYPES.find(b => b.label === state.bodyType)?.prompt || "";
      const newImages: FashionImageItem[] = [];
      if (state.scenario.length > 0) {
        state.scenario.forEach(s => {
          newImages.push({
            id: `img-${s.id}-${Date.now()}`, outfitIndex: s.outfitIndex, url: '', loading: true, regenNote: '',
            videoPrompt: '', isPromptLoading: false, isPromptVisible: false, scenarioPart: s.poseDescription
          });
        });
      } else {
        for (let i = 0; i < validOutfits.length; i++) {
          for (let j = 0; j < 2; j++) {
            newImages.push({
              id: `outfit-${i}-img-${j}-${Date.now()}`, outfitIndex: i, url: '', loading: true, regenNote: '',
              videoPrompt: '', isPromptLoading: false, isPromptVisible: false
            });
          }
        }
      }
      setState(p => ({ ...p, images: newImages }));
      for (let i = 0; i < validOutfits.length; i++) {
        const outfitPart = await service.fileToGenerativePart(validOutfits[i]);
        const outfitDescription = await service.describeOutfit(outfitPart);
        const itemsToGen = newImages.filter(img => img.outfitIndex === i);
        for (const item of itemsToGen) {
          try {
            const url = await service.generateFashionImage(facePart, outfitPart, outfitDescription, state.backgroundNotes, bgPart, state.characterDescription, "", state.imageStyle, state.gender, bodyTypePrompt, state.selectedActions, item.scenarioPart);
            setState(p => ({ ...p, images: p.images.map(img => img.id === item.id ? { ...img, url, loading: false } : img) }));
          } catch (e) { setState(p => ({ ...p, images: p.images.map(img => img.id === item.id ? { ...img, loading: false } : img) })); }
        }
      }
    } finally { setState(p => ({ ...p, isGenerating: false })); }
  };

  const handleRegenImage = async (id: string) => {
    const item = state.images.find(img => img.id === id);
    const validOutfits = state.outfitFiles.filter(f => f !== null) as File[];
    if (!item || !state.faceFile || validOutfits.length <= item.outfitIndex) return;
    setState(p => ({ ...p, images: p.images.map(img => img.id === id ? { ...img, loading: true } : img) }));
    try {
      const facePart = await service.fileToGenerativePart(state.faceFile);
      const outfitPart = await service.fileToGenerativePart(validOutfits[item.outfitIndex]);
      const bgPart = state.backgroundFile ? await service.fileToGenerativePart(state.backgroundFile) : null;
      const bodyTypePrompt = BODY_TYPES.find(b => b.label === state.bodyType)?.prompt || "";
      const outfitDescription = await service.describeOutfit(outfitPart);
      const url = await service.generateFashionImage(facePart, outfitPart, outfitDescription, state.backgroundNotes, bgPart, state.characterDescription, item.regenNote, state.imageStyle, state.gender, bodyTypePrompt, state.selectedActions, item.scenarioPart);
      setState(p => ({ ...p, images: p.images.map(img => img.id === id ? { ...img, url, loading: false } : img) }));
    } catch (e) { setState(p => ({ ...p, images: p.images.map(img => img.id === id ? { ...img, loading: false } : img) })); }
  };

  const handleGenPrompt = async (id: string) => {
    const item = state.images.find(img => img.id === id);
    if (!item || !item.url) return;
    setState(p => ({ ...p, images: p.images.map(img => img.id === id ? { ...img, isPromptLoading: true, isPromptVisible: true } : img) }));
    try {
      const prompt = await service.generateFashionVeoPrompt(item.url, state.backgroundNotes, state.characterDescription, item.regenNote, state.imageStyle, state.gender, state.selectedActions);
      setState(p => ({ ...p, images: p.images.map(img => img.id === id ? { ...img, videoPrompt: prompt, isPromptLoading: false } : img) }));
    } catch (e) { setState(p => ({ ...p, images: p.images.map(img => img.id === id ? { ...img, isPromptLoading: false } : img) })); }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-10">
      <div className="bg-white rounded-[2rem] p-10 mb-12 shadow-sm border border-slate-200">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
          <div className="lg:col-span-5 space-y-8 border-r border-slate-50 pr-0 lg:pr-8">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Giới tính</label>
                <select value={state.gender} onChange={e => setState(p => ({ ...p, gender: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-orange-50 appearance-none transition-all">
                  <option value="Nữ">Nữ</option><option value="Nam">Nam</option>
                </select>
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Phong cách</label>
                <div className="flex bg-slate-50 p-1 rounded-2xl border border-slate-200 h-[52px]">
                  <button onClick={() => setState(p => ({ ...p, imageStyle: 'Realistic' }))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${state.imageStyle === 'Realistic' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>Chân thực</button>
                  <button onClick={() => setState(p => ({ ...p, imageStyle: '3D' }))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${state.imageStyle === '3D' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>3D</button>
                </div>
              </div>
            </div>
            <div className="space-y-2">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Dáng người</label>
              <select value={state.bodyType} onChange={e => setState(p => ({ ...p, bodyType: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none appearance-none transition-all">
                {BODY_TYPES.map(bt => <option key={bt.label} value={bt.label}>{bt.label}</option>)}
              </select>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] border-b pb-2">Gương mặt</label>
                <div onClick={() => faceInputRef.current?.click()} className="aspect-[3/4] bg-slate-50 border-2 border-dashed rounded-2xl flex items-center justify-center cursor-pointer overflow-hidden transition-all hover:border-orange-400">
                  {state.facePreview ? <img src={state.facePreview} className="w-full h-full object-cover" /> : <span className="text-[8px] font-black text-slate-400 uppercase">Tải mặt</span>}
                  <input type="file" ref={faceInputRef} onChange={handleFaceUpload} className="hidden" accept="image/*" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] border-b pb-2">Ảnh bối cảnh</label>
                <div onClick={() => backgroundInputRef.current?.click()} className="aspect-[3/4] bg-slate-50 border-2 border-dashed rounded-2xl flex items-center justify-center cursor-pointer overflow-hidden transition-all hover:border-indigo-400">
                  {state.backgroundPreview ? <img src={state.backgroundPreview} className="w-full h-full object-cover" /> : <span className="text-[8px] font-black text-slate-400 uppercase">Tải bối cảnh</span>}
                  <input type="file" ref={backgroundInputRef} onChange={handleBackgroundUpload} className="hidden" accept="image/*" />
                </div>
              </div>
            </div>
            <div className="space-y-2">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Ghi chú bối cảnh</label>
              <textarea value={state.backgroundNotes} onChange={e => setState(p => ({ ...p, backgroundNotes: e.target.value }))} placeholder="VD: Đường phố, studio..." className="w-full h-[80px] p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs outline-none focus:ring-2 focus:ring-orange-50 resize-none" />
            </div>
          </div>
          <div className="lg:col-span-7 space-y-8">
            <div className="space-y-4">
              <label className="block text-[10px] font-black text-slate-500 uppercase border-b pb-2">Trang phục tham chiếu (Max 4)</label>
              <div className="grid grid-cols-4 gap-4">
                {[0, 1, 2, 3].map(idx => (
                  <div key={idx} onClick={() => outfitRefs[idx].current?.click()} className="aspect-[3/4] bg-slate-50 border-2 border-dashed rounded-2xl flex items-center justify-center cursor-pointer overflow-hidden transition-all hover:border-blue-400">
                    {state.outfitPreviews[idx] ? <img src={state.outfitPreviews[idx]!} className="w-full h-full object-cover" /> : <span className="text-[8px] font-black text-slate-400 uppercase">Bộ {idx + 1}</span>}
                    <input type="file" ref={outfitRefs[idx]} onChange={(e) => handleOutfitUpload(idx, e)} className="hidden" accept="image/*" />
                  </div>
                ))}
              </div>
            </div>
            <div className="space-y-3">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Hành động</label>
              <div className="flex flex-wrap gap-2 max-h-[150px] overflow-y-auto p-4 bg-slate-50 rounded-2xl border">
                {FASHION_ACTIONS.map(action => <button key={action} onClick={() => toggleAction(action)} className={`px-3 py-1.5 rounded-full text-[9px] font-bold transition-all border ${state.selectedActions.includes(action) ? 'bg-orange-600 text-white border-orange-600' : 'bg-white text-slate-500 border-slate-200 hover:border-orange-400'}`}>{action}</button>)}
              </div>
            </div>
            <button onClick={handleGenerateImages} disabled={state.isGenerating || !state.faceFile || state.outfitFiles.every(f => f === null)} className="w-full py-5 bg-slate-900 text-white font-black rounded-3xl shadow-2xl hover:bg-black transition-all text-[11px] uppercase tracking-widest disabled:opacity-50">{state.isGenerating ? "ĐANG TẠO..." : "TẠO BỘ SƯU TẬP"}</button>
          </div>
        </div>
      </div>
      {state.scenario.length > 0 && (
        <div className="mb-12"><div className="bg-slate-900 p-8 rounded-[2rem] border shadow-2xl"><h3 className="text-lg font-black text-white uppercase tracking-widest mb-6 border-b pb-4 flex items-center gap-3">STORYBOARD</h3><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">{state.scenario.map((s) => <div key={s.id} className="bg-white/5 p-5 rounded-2xl border border-white/5"><div className="flex justify-between items-center mb-3"><span className="text-[10px] font-black text-orange-500 uppercase">Cảnh #{s.id}</span></div><p className="text-[11px] text-white/80 font-bold">"{s.vibeDescription}"</p><p className="text-[10px] text-orange-200/60 font-mono mt-2">{s.poseDescription}</p></div>)}</div></div></div>
      )}
      {state.images.length > 0 && (
        <div className="space-y-12 pb-32"><div className="flex flex-col md:flex-row justify-between items-center bg-slate-900 p-8 rounded-[2rem] border shadow-2xl"><h3 className="text-2xl font-black text-white uppercase">GALLERY</h3><div className="flex gap-4 w-full md:w-auto"><button onClick={() => { if (typeof JSZip === 'undefined') return alert("Loading..."); const zip = new JSZip(); state.images.forEach((img, i) => { if (img.url) zip.file(`fashion_${i+1}.png`, img.url.split(',')[1], { base64: true }); }); zip.generateAsync({type:"blob"}).then((c:any) => { const l = document.createElement('a'); l.href = URL.createObjectURL(c); l.download = `fashion_${Date.now()}.zip`; l.click(); }); }} className="px-10 py-4 bg-white text-slate-900 text-[10px] font-black rounded-2xl uppercase shadow-xl">ZIP ẢNH</button></div></div><div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-6 md:gap-10">{state.images.map((img) => <div key={img.id} className="bg-white rounded-[2.5rem] border shadow-sm overflow-hidden flex flex-col hover:shadow-2xl transition-all duration-500 relative"><div className="relative aspect-[9/16] bg-slate-50">{img.url && <img src={img.url} className="w-full h-full object-cover" />}{img.loading && <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/20 backdrop-blur-[2px] z-10"><div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-4"></div></div>}</div><div className="p-6 space-y-4 flex-1 flex flex-col"><div className="space-y-1"><label className="text-[8px] font-black text-slate-400 uppercase">Tinh chỉnh</label><textarea value={img.regenNote} onChange={e => setState(p => ({ ...p, images: p.images.map(i => i.id === img.id ? { ...i, regenNote: e.target.value } : i) }))} placeholder="Sửa..." className="w-full h-16 p-3 text-[10px] font-bold bg-slate-50 border rounded-2xl outline-none" /></div><div className="grid grid-cols-2 gap-2 mt-auto"><button onClick={() => handleRegenImage(img.id)} className="py-4 bg-slate-900 text-white text-[9px] font-black rounded-2xl shadow-lg">LẠI</button><button onClick={() => handleGenPrompt(img.id)} className="py-4 bg-orange-50 text-orange-700 text-[9px] font-black rounded-2xl">PROMPT</button></div></div>{img.isPromptVisible && <div className="p-5 bg-slate-900 border-t animate-slideUp"><div className="flex justify-between items-center mb-2"><span className="text-[8px] font-black text-orange-500 uppercase">Video Prompt</span><button onClick={() => navigator.clipboard.writeText(img.videoPrompt)} className="text-[8px] font-black text-white underline uppercase">Copy</button></div><p className="text-[9px] text-slate-300 leading-relaxed italic line-clamp-4">{img.videoPrompt}</p></div>}</div>)}</div></div>
