áp  các phần còn thiếu trong đoạn code dưới đây vào file personificationmodule:


import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/personificationService';
import { PersonificationSegment } from '../types';

declare var JSZip: any;

const PersonificationModule: React.FC = () => {
  const storageKey = "personification_project_v1";
  const [state, setState] = useState<any>({
    healthKeyword: '',
    ctaProduct: '',
    frameCount: 4,
    gender: 'Nữ',
    voice: 'Miền Bắc',
    productFiles: [],
    productPreviews: [],
    isGeneratingScript: false,
    segments: []
  });

  const productInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setState((p: any) => ({ 
          ...p, 
          ...parsed, 
          productFiles: [], 
          productPreviews: [], 
          isGeneratingScript: false,
          segments: (parsed.segments || []).map((s: any) => ({ ...s, image: { ...s.image, url: '' } })) 
        }));
      }
    } catch (e) {}
  }, []);

  useEffect(() => {
    try {
      const { productFiles, productPreviews, isGeneratingScript, segments, ...rest } = state;
      const safeSegments = segments.map((s: any) => ({ ...s, image: { ...s.image, url: '' } }));
      localStorage.setItem(storageKey, JSON.stringify({ ...rest, segments: safeSegments }));
    } catch (e) {}
  }, [state]);

  useEffect(() => {
    const handleExport = () => {
      const exportData = state.segments.map((seg: any, index: number) => ({
        stt: index + 1,
        inputs: {
          healthKeyword: state.healthKeyword,
          ctaProduct: state.ctaProduct,
          settings: {
            gender: state.gender,
            voice: state.voice,
            frameCount: state.frameCount
          }
        },
        script: seg.content,
        outputImage: seg.image?.url || '',
        videoPrompt: seg.videoPrompt?.text || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Nhan_Hoa_Bo_Phan' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj || {}).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData)) return;

      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};
      const settings = smartFind(inputs, ['settings', 'config']) || {};

      const newState = {
        ...state,
        healthKeyword: smartFind(inputs, ['healthKeyword', 'keyword', 'chủ đề']) || state.healthKeyword,
        ctaProduct: smartFind(inputs, ['ctaProduct', 'product', 'sản phẩm']) || state.ctaProduct,
        gender: smartFind(settings, ['gender', 'giới tính']) || state.gender,
        voice: smartFind(settings, ['voice', 'giọng']) || state.voice,
        frameCount: smartFind(settings, ['frameCount', 'count']) || importedData.length,
        segments: []
      };

      const total = importedData.length;
      for (let i = 0; i < total; i++) {
        const item = importedData[i];

        newState.segments.push({
          id: i + 1,
          content: smartFind(item, ['script', 'content', 'text']) || '',
          image: { 
            url: smartFind(item, ['outputImage', 'image', 'base64']) || '', 
            loading: false, 
            regenNote: '' 
          },
          videoPrompt: { 
            text: smartFind(item, ['videoPrompt', 'prompt']) || '', 
            loading: false, 
            visible: true 
          }
        });

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === total - 1 } }));
        await new Promise(r => setTimeout(r, 100));
      }

      setState(newState);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [state]);

  const handleProductUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = (Array.from(e.target.files) as File[]).slice(0, 5);
      const urls = files.map(f => URL.createObjectURL(f));
      setState((p: any) => ({ ...p, productFiles: files, productPreviews: urls }));
    }
  };

  const handleGenerateScript = async () => {
    if (!state.healthKeyword || !state.ctaProduct) return;
    setState((p: any) => ({ ...p, isGeneratingScript: true }));
    try {
      const scripts = await service.generatePersonificationScript(
        state.healthKeyword,
        state.ctaProduct,
        state.frameCount,
        state.gender,
        state.voice
      );
      const newSegments: PersonificationSegment[] = scripts.map((content, i) => ({
        id: i + 1,
        content,
        image: { url: '', loading: false, regenNote: '' },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setState((p: any) => ({ ...p, segments: newSegments, isGeneratingScript: false }));
    } catch (e) {
      setState((p: any) => ({ ...p, isGeneratingScript: false }));
    }
  };

  const handleGenImage = async (id: number) => {
    const seg = state.segments.find((s: any) => s.id === id);
    if (!seg) return;
    setState((p: any) => ({
      ...p,
      segments: p.segments.map((s: any) => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s)
    }));
    try {
      const productParts = await Promise.all(state.productFiles.map((f: any) => service.fileToGenerativePart(f)));
      const url = await service.generatePersonificationImage(
        seg.content,
        productParts,
        state.healthKeyword,
        state.ctaProduct,
        state.gender,
        seg.image.regenNote
      );
      setState((p: any) => ({
        ...p,
        segments: p.segments.map((s: any) => s.id === id ? { ...s, image: { ...s.image, url, loading: false } } : s)
      }));
    } catch (e) {
      setState((p: any) => ({
        ...p,
        segments: p.segments.map((s: any) => s.id === id ? { ...s, image: { ...s.image, loading: false } } : s)
      }));
    }
  };

  const handleGenPrompt = async (id: number) => {
    const seg = state.segments.find((s: any) => s.id === id);
    if (!seg) return;
    setState((p: any) => ({
      ...p,
      segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s)
    }));
    try {
      const prompt = await service.generatePersonificationVeoPrompt(seg.content, state.healthKeyword, state.gender, state.voice);
      setState((p: any) => ({
        ...p,
        segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s)
      }));
    } catch (e) {
      setState((p: any) => ({
        ...p,
        segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s)
      }));
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') {
      alert("Đang tải thư viện nén, vui lòng thử lại sau giây lát.");
      return;
    }
    const zip = new JSZip();
    let count = 0;
    for (let i = 0; i < state.segments.length; i++) {
      const seg = state.segments[i];
      if (seg.image.url) {
        const base64Data = seg.image.url.split(',')[1];
        if (base64Data) {
          const fileName = `${String(i + 1).padStart(2, '0')}.png`;
          zip.file(fileName, base64Data, { base64: true });
          count++;
        }
      }
    }
    if (count === 0) { alert("Không có ảnh nào để tải xuống."); return; }
    try {
      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `nhan_hoa_images_${Date.now()}.zip`;
      link.click();
      URL.revokeObjectURL(link.href);
    } catch (error) { alert("Có lỗi xảy ra khi đóng gói ảnh."); }
  };

  const downloadAllPrompts = () => {
    const text = state.segments.map((s: any) => s.videoPrompt.text).filter((t: string) => t).join('\n');
    if (!text) return;
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'nhan_hoa_prompts.txt';
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">1. Chủ đề sức khỏe (Keyword)</label>
              <input 
                type="text" 
                value={state.healthKeyword}
                onChange={e => setState((p: any) => ({ ...p, healthKeyword: e.target.value }))}
                placeholder="Ví dụ: hút thuốc, uống rượu, thức khuya..."
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 focus:border-orange-500 outline-none transition-all font-bold"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">2. Sản phẩm muốn CTA</label>
              <input 
                type="text" 
                value={state.ctaProduct}
                onChange={e => setState((p: any) => ({ ...p, ctaProduct: e.target.value }))}
                placeholder="Ví dụ: trà thải độc gan, kẹo cai thuốc..."
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 focus:border-orange-500 outline-none transition-all font-bold"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">Giới tính nhân vật</label>
                <select 
                  value={state.gender} 
                  onChange={e => setState((p: any) => ({ ...p, gender: e.target.value }))}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-bold"
                >
                  <option value="Nữ">Nữ</option>
                  <option value="Nam">Nam</option>
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">Giọng điệu vùng miền</label>
                <select 
                  value={state.voice} 
                  onChange={e => setState((p: any) => ({ ...p, voice: e.target.value }))}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-bold"
                >
                  <option value="Miền Bắc">Miền Bắc (Hà Nội)</option>
                  <option value="Miền Nam">Miền Nam (SÀI GÒN)</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">3. Thời lượng video</label>
              <select 
                value={state.frameCount}
                onChange={e => setState((p: any) => ({ ...p, frameCount: parseInt(e.target.value) }))}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-bold"
              >
                {Array.from({ length: 12 }, (_, i) => i + 4).map(n => (
                  <option key={n} value={n}>{n} khung hình - {n * 8}s</option>
                ))}
              </select>
            </div>
          </div>

          <div className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase mb-2">4. Ảnh sản phẩm mẫu (Tối đa 5)</label>
              <div 
                onClick={() => productInputRef.current?.click()}
