    } catch (e) {
      setState((p: any) => ({
        ...p,
        segments: p.segments.map((s: any) => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s)
      }));
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') {
      alert("Đang tải thư viện nén, vui lòng thử lại sau giây lát.");
      return;
    }

    const zip = new JSZip();
    let count = 0;

    for (let i = 0; i < state.segments.length; i++) {
      const seg = state.segments[i];
      if (seg.image.url) {
        const base64Data = seg.image.url.split(',')[1];
        if (base64Data) {
          const fileName = `${String(i + 1).padStart(2, '0')}.png`;
          zip.file(fileName, base64Data, { base64: true });
          count++;
        }
      }
    }

    if (count === 0) {
      alert("Không có ảnh nào để tải xuống.");
      return;
    }

    try {
      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `nhan_hoa_images_${Date.now()}.zip`;
      link.click();
      URL.revokeObjectURL(link.href);
    } catch (error) {
      console.error("Lỗi khi tạo file ZIP:", error);
      alert("Có lỗi xảy ra khi đóng gói ảnh.");
    }
  };

  const downloadAllPrompts = () => {
    const text = state.segments
      .map((s: any) => s.videoPrompt.text)
      .filter((t: string) => t)
      .join('\n');
    if (!text) return;
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
