                    </div>
                  )}
                  <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-3 py-1.5 rounded-full border border-slate-700">
                    CẢNH #{seg.id}
                  </div>
                </div>

                <div className="p-6 flex flex-col flex-1 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-orange-600 uppercase">Lời thoại nhân vật:</label>
                    <textarea 
                      value={seg.content}
                      onChange={e => setState((p: any) => ({
                        ...p,
                        segments: p.segments.map((s: any) => s.id === seg.id ? { ...s, content: e.target.value } : s)
                      }))}
                      className="w-full h-32 p-3 text-xs font-bold text-slate-700 bg-slate-50 border border-100 rounded-xl focus:bg-white focus:border-orange-500 transition-all outline-none resize-none leading-relaxed"
                    />
                    <div className="text-right">
                      <span className={`text-[8px] font-black ${seg.content.length > 190 ? 'text-red-500' : 'text-slate-300'}`}>
                        {seg.content.length}/190
                      </span>
                    </div>
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase">Ghi chú sửa ảnh:</label>
                    <textarea 
                      value={seg.image.regenNote}
                      onChange={e => setState((p: any) => ({
                        ...p,
                        segments: p.segments.map((s: any) => s.id === seg.id ? { ...s, image: { ...s.image, regenNote: e.target.value } } : s)
                      }))}
                      placeholder="VD: Đổi nền sáng hơn..."
                      className="w-full h-16 p-3 text-[10px] font-bold text-slate-500 bg-slate-50 border border-slate-100 border-dashed rounded-xl outline-none resize-none"
                    />
                  </div>

                  <div className="mt-auto grid grid-cols-2 gap-2 pt-4">
                    <button 
                      onClick={() => handleGenImage(seg.id)}
                      disabled={seg.image.loading}
                      className="py-3 bg-slate-900 text-white text-[10px] font-black rounded-xl hover:bg-black transition-all uppercase tracking-tighter"
                    >
                      {seg.image.url ? "Tạo lại ảnh" : "Tạo ảnh 3D"}
                    </button>
                    <button 
                      onClick={() => handleGenPrompt(seg.id)}
                      disabled={seg.videoPrompt.loading}
                      className="py-3 bg-orange-50 text-orange-600 text-[10px] font-black rounded-xl border border-orange-100 hover:bg-orange-100 transition-all uppercase tracking-tighter"
                    >
                      Prompt
                    </button>
                  </div>
                </div>

                {seg.videoPrompt.visible && (
                  <div className="p-4 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-[8px] font-black text-orange-500 uppercase">Video Prompt sẵn sàng</span>
                      <button 
                        onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)}
                        className="text-[8px] font-black text-white underline"
                      >
                        COPY
                      </button>
                    </div>
                    <p className="text-[9px] text-slate-300 leading-tight line-clamp-4 italic opacity-80 font-medium">
                      "{seg.videoPrompt.text}"
                    </p>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default PersonificationModule;

